xmcp.oas.datatype.OASValidationResult result = new xmcp.oas.datatype.OASValidationResult();
result.setErrorMessages(new ArrayList<String>());
// validate TestMeasureDefinition.captureFrequency of type String
try {
    var validator_captureFrequency = new com.gip.xyna.openapi.StringTypeValidator();
    validator_captureFrequency.setName("captureFrequency");
    validator_captureFrequency.setValue(getCaptureFrequency());
    result.getErrorMessages().addAll(validator_captureFrequency.checkValid());
} catch (Exception e) {
    result.getErrorMessages().add("Error: could not validate TestMeasureDefinition.captureFrequency");
}

